"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[294],{7448:(D,B,t)=>{t.r(B),t.d(B,{data:()=>l});const l=JSON.parse('{"key":"v-460bb47e","path":"/%D0%BF%D1%80%D0%B0%D0%B2%D0%B8%D0%BB%D1%8C%D0%BD%D1%8B%D0%B9-%D0%B2%D0%B7%D0%B3%D0%BB%D1%8F%D0%B4-%D0%BD%D0%B0-%D1%85%D1%83%D0%B4%D0%BE%D0%B6%D0%B5%D1%81%D1%82%D0%B2%D0%B5%D0%BD%D0%BD%D0%BE%D0%B5-%D0%BF%D1%80%D0%BE%D0%B8%D0%B7%D0%B2%D0%B5%D0%B4%D0%B5%D0%BD%D0%B8%D0%B5.html","title":"Правильный взгляд на художественное произведение","lang":"ru-RU","frontmatter":{"title":"Правильный взгляд на художественное произведение","date":"2024-04-24","categories":["Самообразование"],"tags":["Художественная литература"]},"excerpt":"","headers":[],"git":{"updatedTime":1713974757000},"filePathRelative":"правильный-взгляд-на-художественное-произведение.md"}')},8895:(D,B,t)=>{t.r(B),t.d(B,{default:()=>f});var l=t(6252),e=t(3577);const r={id:"frontmatter-title",tabindex:"-1"},n=(0,l._)("a",{class:"header-anchor",href:"#frontmatter-title","aria-hidden":"true"},"#",-1),a=(0,l._)("p",null,[(0,l._)("strong",null,"24.04.2024")],-1),u=(0,l._)("p",null,"Чтение хорошей художественной книги имеет сходство с чтением Капитала: понимание не даётся легко, нужно приложить усилие. В определенном смысле, Капитал даже проще, для него есть набор представлений куда смотреть: понять капиталистические общественные отношения, понять логику Маркса, понять диалектический метод. Для художественной литературы направление найти труднее; смотреть на сюжет? На художественный образ? Зачем?",-1),_=(0,l._)("p",null,"Говоря о правильном взгляде на художественное произведение, по аналогии с научными книгами, на ум приходит существование некоторой правильной интерпретации и остальных — неправильных. Не обратил внимание на важную часть сюжета, неверно понял мотив героя; кажется, что всё это не относится с сути дела, к правильному взгляду на художественное произведение. Рассмотрим цитату из книги Евгения Богата «Ахилл и черепаха».",-1),i=(0,l._)("blockquote",null,[(0,l._)("p",null,"Может быть, этот фильм — не по воле его авторов, разумеется, — и подсказал герою вашей будущей статьи определенный образ действия. Он вынес из фильма не боль за человека. Не это — помните? — удивленное и беззащитное, как у наказанного невесть за что ребенка, лицо стареющей женщины. Не отвращение к миру, в котором смех перестает быть смехом, потому что может рассмешить только горе, только слезы. Нет! Он вынес идею розыгрыша… Сюжет утратил для него философское, эмоциональное содержание, стал руководством к подлости.[^1]")],-1),o=(0,l._)("p",null,"Что означает в данном случае «утратил для него философское, эмоциональное содержание»? Эмоциональное содержание может быть только если есть связь между мной, событиями и героями книги. Такая связь показывает внутреннюю работу. При чтении Капитала, внутренняя работа представляется в перестройке своего знания, мыслей. Внутренняя работа при чтении художественной книги аналогична, только её предмет отличен.",-1),s={href:"https://ru.wikisource.org/wiki/%D0%9A%D0%B0%D0%BA_%D1%8F_%D1%80%D0%B5%D0%B4%D0%B0%D0%BA%D1%82%D0%B8%D1%80%D0%BE%D0%B2%D0%B0%D0%BB_%D1%81%D0%B5%D0%BB%D1%8C%D1%81%D0%BA%D0%BE%D1%85%D0%BE%D0%B7%D1%8F%D0%B9%D1%81%D1%82%D0%B2%D0%B5%D0%BD%D0%BD%D1%83%D1%8E_%D0%B3%D0%B0%D0%B7%D0%B5%D1%82%D1%83_(%D0%A2%D0%B2%D0%B5%D0%BD;_%D0%92._%D0%9E._%D0%A2.)",target:"_blank",rel:"noopener noreferrer"},p=(0,l._)("p",null,"Можно, например, сопоставить себя с человеком который приходит к рассказчику и говорит следующее:",-1),k=(0,l._)("blockquote",null,[(0,l._)("p",null,"До свиданья, сударь, будьте здоровы! Вы сняли с души моей великую тяжесть! Если мой рассудок выдержал испытание посредством ваших сельско-хозяйственных статей, то я глубоко убежден, что теперь уже я его никогда не потеряю. Будьте очень здоровы, сударь!")],-1),d=(0,l._)("p",null,[(0,l.Uk)("Этот герой рассказа потерял самообладание когда читал бред рассказчика и пришел к рассказчику чтобы убедится в своей вменяемости. Представляя себя месте этого человека, а кого-угодно на месте несущего бред рассказчика, я самоутверждаюсь в моих мыслях: все несут бред, а я умнее их. "),(0,l._)("strong",null,"Вместо инструмента развития рассказ становится средством закрепления недостатков."),(0,l.Uk)(" Другой результат выходи если посмотреть "),(0,l._)("strong",null,"на себя"),(0,l.Uk)(", увидеть в себе рассказчика из рассказа, который говорит о том, в чём плохо разбирается. Увидеть и попытаться устранить. Использовать рассказ как начало самокритики.")],-1),h=(0,l._)("p",null,"При таком подходе правильность и неправильность понимания художественного произведения наделяется другим значением. Правильно понять книгу — лучше понять себя, понять и одновременно попытаться улучшить. И не особо важно, послужит ли толчком основной сюжет или второстепенная деталь, этот ли смысл автор думал, что вкладывает в своё произведение или другой.",-1),c={},f=(0,t(3744).Z)(c,[["render",function(D,B){const t=(0,l.up)("ExternalLinkIcon");return(0,l.wg)(),(0,l.iD)("div",null,[(0,l._)("h1",r,[n,(0,l.Uk)(" "+(0,e.zw)(D.$frontmatter.title),1)]),a,u,_,i,o,(0,l._)("p",null,[(0,l.Uk)("Возьмем для примера небольшой рассказ Марка Твена «"),(0,l._)("a",s,[(0,l.Uk)("Как я редактировал сельскохозяйственную газету"),(0,l.Wm)(t)]),(0,l.Uk)("». Это рассказ про человека который ни в чём не разбирается и одновременно воинственно защищает дилетантизм. В рассказе, в пародийной форме, обыгран приоритет СМИ на продажах и количестве подписчиков вместо содержания публикаций. «Чем меньше человек знает, тем больше может обратить на себя внимание и тем большего уважения к себе может требовать!». Богатый материал, чтобы начать размышление. Что же можно извлечь из рассказа смотря на него неправильно?")]),p,k,d,h])}]])}}]);